// Wyciągnij i sparsuj JSON z odpowiedzi Gemini
const response = $input.first().json;
const rawText = response.candidates?.[0]?.content?.parts?.[0]?.text || '';

// Usuń ewentualne markdown code blocks
const cleanText = rawText
  .replace(/^```json\n?/, '')
  .replace(/\n?```$/, '')
  .trim();

let article;
try {
  article = JSON.parse(cleanText);
} catch (e) {
  throw new Error('AI nie zwróciło poprawnego JSON: ' + rawText.substring(0, 300));
}

if (!article.title || !article.slug || !article.content) {
  throw new Error('Brakuje wymaganych pól w odpowiedzi AI.');
}

// Normalizuj slug
article.slug = article.slug
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '');

return [{ json: article }];

