// Wyciągnij base64 z odpowiedzi Gemini Image API
// i wgraj do Supabase Storage

const imageResponse = $input.first().json;
const article = $('Parsuj odpowiedź AI').first().json;

// Szukamy części z obrazem w odpowiedzi
const parts = imageResponse.candidates?.[0]?.content?.parts || [];
const imagePart = parts.find(p => p.inlineData?.mimeType?.startsWith('image/'));

if (!imagePart) {
  // Brak obrazu — kontynuujemy bez okładki
  console.warn('Gemini nie wygenerował obrazu — artykuł zostanie opublikowany bez okładki.');
  return [{ json: { cover_image: null, article } }];
}

const base64Data = imagePart.inlineData.data;
const mimeType = imagePart.inlineData.mimeType || 'image/png';
const ext = mimeType.split('/')[1] || 'png';
const filename = `blog-cover-${article.slug}-${Date.now()}.${ext}`;

// Zdekoduj base64 do binary
const imageBuffer = Buffer.from(base64Data, 'base64');

// Wgraj do Supabase Storage
const supabaseUrl = $env.SUPABASE_URL;
const serviceKey = $env.SUPABASE_SERVICE_KEY;

if (!supabaseUrl || !serviceKey) {
  throw new Error('Brak zmiennych SUPABASE_URL lub SUPABASE_SERVICE_KEY w n8n.');
}

const uploadResponse = await fetch(
  `${supabaseUrl}/storage/v1/object/blog-covers/${filename}`,
  {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${serviceKey}`,
      'Content-Type': mimeType,
      'x-upsert': 'true'
    },
    body: imageBuffer
  }
);

if (!uploadResponse.ok) {
  const err = await uploadResponse.text();
  console.error('Błąd uploadu do Supabase Storage:', err);
  return [{ json: { cover_image: null, article } }];
}

// Publiczny URL obrazu
const publicUrl = `${supabaseUrl}/storage/v1/object/public/blog-covers/${filename}`;
console.log(`Obraz wgrany: ${publicUrl}`);

return [{ json: { cover_image: publicUrl, article } }];

// Przygotuj finalny payload dla webhooka /api/blog/publish
const { cover_image, article } = $input.first().json;

return [{
  json: {
    slug: article.slug,
    title: article.title,
    content: article.content,
    excerpt: article.excerpt || null,
    cover_image: cover_image || null,
    author: 'Zautomatyzujemy',
    tags: article.tags || [],
    published_at: new Date().toISOString()
  }
}];

const result = $input.first().json;
const article = $('Przygotuj payload').first().json;

console.log(`✅ Opublikowano: "${article.title}"`);
console.log(`URL: ${result.url || '/blog/' + article.slug}`);

return [{ json: { success: true, title: article.title, url: result.url } }];
